select.isEqual:
SELECT TBL_APRDOCINFO.DOCID, TBL_APRDOCINFO.HREF, TBL_APRRECEIPTPROCESSINFO.SENTDEPTNAME, TBL_APRRECEIPTPROCESSINFO.SENTDEPTNAME$v_LANGTYPE$, TBL_APRDOCINFO.DOCTITLE, TBL_APRRECEIPTPROCESSINFO.DOCSTATE, TBL_APRRECEIPTPROCESSINFO.APRSTATE, TBL_APRDOCINFO.HASOPINIONYN, TBL_APRDOCINFO.DOCTYPE FROM TBL_APRRECEIPTPROCESSINFO INNER JOIN TBL_APRDOCINFO ON TBL_APRRECEIPTPROCESSINFO.DOCID = TBL_APRDOCINFO.DOCID AND TBL_APRRECEIPTPROCESSINFO.TENANT_ID = TBL_APRDOCINFO.TENANT_ID INNER JOIN TBL_EXPAPRDOCINFO ON TBL_EXPAPRDOCINFO.DOCID = TBL_APRDOCINFO.DOCID AND TBL_EXPAPRDOCINFO.TENANT_ID = TBL_APRDOCINFO.TENANT_ID WHERE TBL_APRRECEIPTPROCESSINFO.PROCESSYN <> 'Y' AND TBL_APRRECEIPTPROCESSINFO.TENANT_ID = #v_TENANTID# AND (((TBL_APRRECEIPTPROCESSINFO.PROCESSORID = #v_USERID# AND TBL_APRRECEIPTPROCESSINFO.RECEIVEDDEPTID = #v_DEPTID#) AND (TBL_APRRECEIPTPROCESSINFO.APRSTATE = '012' OR TBL_APRRECEIPTPROCESSINFO.APRSTATE = '015'))
OR (TBL_APRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN ($v_DEPTIDS$) AND TBL_APRRECEIPTPROCESSINFO.APRSTATE IN ('011', '014')) OR (TBL_APRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN ($ v_DEPTIDS$) AND TBL_APRRECEIPTPROCESSINFO.APRSTATE = '015')
) ORDER BY PROCESSDATE $v_BASICORDER$ LIMIT #v_LISTCOUNT#

