sqlMap.insert:
INSERT 	INTO  TBL_HISTORYATTACHINFO ( 
			DOCID,    ATTACHFILESN, ATTACHFILENAME, ATTACHFILEDISPLAYNAME, ATTACHFILEHREF, ATTACHFILESIZE, ATTACHUSERID, ATTACHUSERNAME, ATTACHUSERNAME2, ATTACHUSERJOBTITLE, ATTACHUSERJOBTITLE2, ATTACHUSERDEPTID, ATTACHUSERDEPTNAME, ATTACHUSERDEPTNAME2, MODIFYDATE, 										MODIFYSN,     MODIFYFLAG,    PAGENUM,   CHKFLAG, TENANT_ID, COMPANYID
)  VALUES (#v_DOCID#, $v_ATTACHSN$, #v_ATTACHNAME#, #v_ATTACHDISPNAME#,    #v_ATTACHHREF#, $v_ATTACHSIZE$, #v_USERID#,    #v_USERNAME#,   #v_USERNAME2#,   #v_USERJOBTITLE#,   #v_USERJOBTITLE2#,    #v_USERDEPTID#, #v_USERDEPTNAME#,   #v_USERDEPTNAME2#,    #v_SYSDATE# , $v_MODIFYSN$, #v_MODIFYFLAG#, $v_PAGENUM$,  ' ' , $v_TENANTID$, #companyID#)

